DROP TABLE IF EXISTS `server_metrics`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `server_metrics` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `server_id` bigint unsigned NOT NULL,
  `cpu_load_1min` decimal(8,2) DEFAULT NULL,
  `cpu_load_5min` decimal(8,2) DEFAULT NULL,
  `cpu_load_15min` decimal(8,2) DEFAULT NULL,
  `cpu_usage_percent` decimal(5,2) DEFAULT NULL,
  `memory_total` bigint DEFAULT NULL COMMENT 'in MB',
  `memory_used` bigint DEFAULT NULL COMMENT 'in MB',
  `memory_free` bigint DEFAULT NULL COMMENT 'in MB',
  `memory_percent` decimal(5,2) DEFAULT NULL,
  `disk_total` bigint DEFAULT NULL COMMENT 'in GB',
  `disk_used` bigint DEFAULT NULL COMMENT 'in GB',
  `disk_free` bigint DEFAULT NULL COMMENT 'in GB',
  `disk_percent` decimal(5,2) DEFAULT NULL,
  `network_rx_bytes` bigint DEFAULT NULL COMMENT 'received bytes',
  `network_tx_bytes` bigint DEFAULT NULL COMMENT 'transmitted bytes',
  `process_count` int DEFAULT NULL,
  `uptime_seconds` int DEFAULT NULL,
  `is_online` tinyint(1) NOT NULL DEFAULT '1',
  `recorded_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `server_metrics_server_id_recorded_at_index` (`server_id`,`recorded_at`),
  KEY `server_metrics_recorded_at_index` (`recorded_at`),
  CONSTRAINT `server_metrics_server_id_foreign` FOREIGN KEY (`server_id`) REFERENCES `failover_servers` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=916 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

